from peft import PeftModel


class CricketEntityType(Enum):
    PLAYER = "player"
    TEAM = "team"
    VENUE = "venue"
    STATISTIC = "statistic"
    FORMAT = "format"


@dataclass
class CricketKnowledgeBase:
    """Cricket statistical knowledge for grounding responses"""

    player_stats: Dict[str, Dict] = None
    team_records: Dict[str, Dict] = None
    venue_stats: Dict[str, Dict] = None

    def __post_init__(self):
        if self.player_stats is None:
            self.player_stats = {
                "Virat Kohli": {
                    "t20_average": 52.5,
