                    "test_average": 58.2,
                    "weakness": "leg-spin around off-stump",
                    "strength": "short-pitched deliveries against pace"
                },
                "Jasprit Bumrah": {
                    "t20_economy": 6.8,
                    "test_average": 20.4,
                    "specialty": "death overs, yorker accuracy",
                    "strike_rate": 115.0
                },
                "Rohit Sharma": {
                    "t20_average": 34.0,
                    "t20_sr": 136.8,
                    "opening_sr": 142.3,
                    "powerplay_avg": 42.1
                }
            }

        if self.team_records is None:
            self.team_records = {
                "RCB": {"t20_win_pct": 0.52, "avg_first_inning_score": 168},
                "MI": {"t20_win_pct": 0.58, "avg_first_inning_score": 165},
