@dataclass
class CricketGenerationConfig:
    """Configuration for cricket-aware text generation"""
    max_length: int = 256
    temperature: float = 0.7
    top_p: float = 0.9
    repetition_penalty: float = 1.2
    num_beams: int = 1


class CricketLLMInference:
    """Inference engine for cricket domain LLM"""

    CRICKET_PROMPTS = {
        "player_analysis": """
<MATCH_START>
Instruction: Analyze player performance
Input: {input}
<CRICKET_STATS>
Response:""",
        "match_strategy": """
<MATCH_START>
Instruction: Provide match strategy recommendation
Input: {input}
<CRICKET_STATS>
Response:""",
        "statistical_comparison": """
<MATCH_START>
Instruction: Compare cricket statistics
Input: {input}
<CRICKET_STATS>
Response:""",
    }

    def __init__(
        self,
        base_model: str = "gpt2",
        adapter_path: Optional[str] = None,
        knowledge_base: Optional[CricketKnowledgeBase] = None
    ):
        self.base_model_name = base_model
        self.adapter_path = adapter_path
        self.knowledge_base = knowledge_base or CricketKnowledgeBase()
        self.tokenizer = None
        self.model = None
        self.generator = None
        self._initialize_model()

    def _initialize_model(self):
        """Load base model with LoRA adapter"""
        print(f"Loading base model: {self.base_model_name}")
        self.tokenizer = AutoTokenizer.from_pretrained(self.base_model_name)
        self.tokenizer.pad_token = self.tokenizer.eos_token

        self.model = AutoModelForCausalLM.from_pretrained(
            self.base_model_name,
            device_map="auto" if torch.cuda.is_available() else None,
            torch_dtype=torch.float32
        )

        # Load LoRA adapter if provided
        if self.adapter_path:
            print(f"Loading LoRA adapter from: {self.adapter_path}")
            try:
                self.model = PeftModel.from_pretrained(
                    self.model,
                    self.adapter_path
                )
                print("✓ LoRA adapter loaded successfully")
            except Exception as e:
                print(f"⚠ Warning: Could not load LoRA adapter: {e}")

        # Create text generation pipeline
        self.generator = pipeline(
            "text-generation",
            model=self.model,
            tokenizer=self.tokenizer,
            device=0 if torch.cuda.is_available() else -1
        )

    def extract_cricket_entities(
        self,
        text: str
    ) -> Dict[CricketEntityType, List[str]]:
        """Extract cricket entities (players, teams, etc.) from text"""
        entities = {
            CricketEntityType.PLAYER: [],
            CricketEntityType.TEAM: [],
            CricketEntityType.VENUE: [],
            CricketEntityType.STATISTIC: [],
            CricketEntityType.FORMAT: []
        }

        players = ["Virat Kohli", "Rohit Sharma", "Jasprit Bumrah", "AB de Villiers"]
        teams = ["RCB", "MI", "CSK", "DC", "KKR", "India", "Australia"]
        venues = ["Wankhede Stadium", "Eden Gardens", "MCG"]
        stats = ["strike rate", "economy", "average", "run rate"]
        formats = ["T20", "ODI", "Test"]

        for player in players:
            if player in text:
                entities[CricketEntityType.PLAYER].append(player)
        for team in teams:
            if team in text:
                entities[CricketEntityType.TEAM].append(team)
        for venue in venues:
            if venue in text:
                entities[CricketEntityType.VENUE].append(venue)
        for stat in stats:
            if stat in text:
                entities[CricketEntityType.STATISTIC].append(stat)
        for fmt in formats:
            if fmt in text:
                entities[CricketEntityType.FORMAT].append(fmt)

        return entities

