if __name__ == "__main__":
    # Initialize inference engine
    print("Initializing Cricket Domain LLM...\n")
    inference = CricketLLMInference(
        base_model="gpt2",
        adapter_path=None,  # Set to "models/adapters/cricket_lora" if available
        knowledge_base=CricketKnowledgeBase()
    )

    # Initialize evaluator
    evaluator = CricketDomainEvaluator(inference.knowledge_base)

    # Test queries
    test_queries = [
        {
            "query": "Analyze Virat Kohli's performance in T20 cricket",
            "task_type": "player_analysis"
        },
        {
            "query": "What bowling strategy should be used at Eden Gardens against aggressive batsmen?",
            "task_type": "match_strategy"
        },
        {
            "query": "Compare Jasprit Bumrah and Mohammed Siraj in death overs",
            "task_type": "statistical_comparison"
        }
    ]

    print("="*70)
    print("Cricket Domain LLM Inference Results")
    print("="*70)

    for test in test_queries:
        print(f"\n\n{'─'*70}")
        result = inference.generate_response(test["query"], test["task_type"])

        print(f"\nTask: {result['task_type']}")
        print(f"Query: {result['query']}")
        print(f"\nIdentified Entities:")
        for entity_type, entities in result['entities'].items():
            if entities:
                print(f"  {entity_type}: {', '.join(entities)}")

        print(f"\nGenerated Response:")
        print(f"  {result['response'][:300]}...")

        # Evaluate
        metrics = evaluator.evaluate_response(
            result['response'],
            test['query'],
            {CricketEntityType[k.upper()]: v for k, v in result['entities'].items()}
        )
        print(f"\nEvaluation Metrics:")
        for metric, score in metrics.items():
            print(f"  {metric}: {score:.3f}")

    print(f"\n\n{'='*70}")
    print("✓ Cricket Domain LLM Inference Complete")
